solutionFiles.content:
class Book:
    def __init__(self, title, price):
        self.title = title
        self.price = price

    def price_tag(self):
        return f"{self.title} - ${self.price}"


class Course:
    def __init__(self, title, price):
        self.title = title
        self.price = price

    def price_tag(self):
        return f"{self.title} - ${self.price}"

print(Book("Python 101", 12).price_tag())
print(Course("Team Training", 25).price_tag())

